function rewriteLinks(content) {
  return content
    .replace(/\]\(\/zh\//g, '](__ZH__')
    .replace(/\]\(\/(guide|components|theme|icons|layout)\//g, '](/zh/$1/')
    .replace(/\]\(\/(guide|components|theme|icons|layout)\)/g, '](/zh/$1/)')
    .replace(/\]\(__ZH__/g, '](/zh/')
}

function translateSectionHeaders(content) {
  return content.replace(/^## (.+)$/gm, (match, title) => {
    const clean = title.replace(/ <Badge[^>]*\/>/g, '').trim()
    const zh = sectionTitleZh[clean]
    if (!zh) return match
    const badge = title.includes('<Badge') ? title.slice(clean.length) : ''
    return `## ${zh}${badge}`
  })
}

function translatePageTitle(content, fileBase) {
  const titleMap = {
    README: 'Button',
    alert: 'Alert',
    loading: 'Loading',
    input: 'Input',
    checkbox: 'Checkbox',
    switch: 'Switch',
    select: 'Select',
    avatar: 'Avatar',
    notification: 'Notification',
    radio: 'Radio',
    tooltip: 'Tooltip',
    dialog: 'Dialog',
    pagination: 'Pagination',
    table: 'Table',
    navbar: 'Navbar',
    sidebar: 'Sidebar',
    card: 'Card',
    'time-select': 'Time select',
    scrollbar: 'Scrollbar',
    rate: 'Rate',
    badge: 'Badge',
    popper: 'Popper',
  }
  const name = fileBase === 'README' ? 'Button' : titleMap[fileBase] || fileBase
  return content.replace(/^# .+$/m, `# ${name}`)
}

function injectZhDescription(content, fileBase) {
  const desc = pageDescriptionZh[fileBase]
  if (!desc || content.includes('\ndescription:')) return content
  if (!content.startsWith('---')) return content
  const end = content.indexOf('\n---\n', 4)
  if (end < 0) return content
  const fm = content.slice(0, end)
  const body = content.slice(end)
  if (fm.includes('description:')) {
    return content.replace(
      /^description:.*$/m,
      `description: ${JSON.stringify(desc)}`
    )
  }
  return `${fm}\ndescription: ${JSON.stringify(desc)}${body}`
}

function syncMarkdownFile(relPath) {
  const src = path.join(docsDir, relPath)
  const dest = path.join(zhDir, relPath)
  if (!fs.existsSync(src)) return
  const fileBase = path.basename(relPath, '.md')
  const dirBase = path.basename(path.dirname(relPath))
  const key = dirBase === 'components' ? fileBase : fileBase

  let content = fs.readFileSync(src, 'utf8')
  content = rewriteLinks(content)
  content = translateSectionHeaders(content)
  if (dirBase === 'components') {
    content = translatePageTitle(content, fileBase)
    content = injectZhDescription(content, key === 'README' ? 'button' : key)
  }
  fs.mkdirSync(path.dirname(dest), { recursive: true })
  fs.writeFileSync(dest, content)
}

